  try {
    const rawBody = req.rawBody;
    verifySignature(rawBody, req.headers["x-signature"]);
    const payload = JSON.parse(rawBody);
    await db.insertEvent(payload);
    next();
  } catch (err) {
    next(err);
  }
}

